# composite keys: (city, year) -> value
rainfall = {
    ("NYC", 2025): 47.3,
    ("NYC", 2026): 51.1,
    ("LA", 2026): 14.2,
}
print(rainfall[("NYC", 2026)])   # 51.1

# a list can't be a key, but a tuple can
try:
    {[1, 2]: "nope"}
except TypeError as e:
    print("list key fails:", e)

a = {1, 2, 3, 4}
b = {3, 4, 5, 6}

print(a | b)   # union: {1, 2, 3, 4, 5, 6}
print(a & b)   # intersection: {3, 4}
print(a - b)   # difference: {1, 2}
print(a ^ b)   # symmetric difference: {1, 2, 5, 6}

print({1, 2} <= a)   # subset? True
print(a >= {1, 9})   # superset? False

# frozenset: immutable + hashable
key = frozenset({"read", "write"})
permissions = {key: "editor"}
print(permissions[frozenset({"write", "read"})])  # editor

user = {"name": "Ada", "age": 36}

print(user["name"])              # Ada
print(user.get("email", "n/a"))  # n/a (no KeyError)

user["email"] = "ada@example.com"  # add / update
del user["age"]                   # remove a key

for key, value in user.items():
    print(f"{key}: {value}")

print("name" in user)             # True (checks keys)

# merge (Python 3.9+); right-hand keys win
defaults = {"theme": "light", "lang": "en"}
chosen = defaults | {"theme": "dark"}
print(chosen)                     # {'theme': 'dark', 'lang': 'en'}

from collections import Counter, defaultdict

words = "the cat sat on the mat the cat".split()

counts = Counter(words)
print(counts)                     # Counter({'the': 3, 'cat': 2, ...})
print(counts.most_common(2))      # [('the', 3), ('cat', 2)]

# group words by their first letter, no missing-key guard needed
groups = defaultdict(list)
for w in words:
    groups[w[0]].append(w)
print(dict(groups))               # {'t': [...], 'c': [...], ...}

# dict comprehension: square each number
squares = {n: n * n for n in range(1, 6)}
print(squares)                    # {1: 1, 2: 4, 3: 9, 4: 16, 5: 25}

